mapper.select:
SELECT COUNT(*)
FROM ddd_log
WHERE log_number = #{logNumber}
  AND user_number = #{userNumber}

mapper.update:
UPDATE ddd_log_comment
SET comment_post = #{commentPost}
WHERE comment_number = #{commentNumber}
  AND user_number = #{userNumber}

mapper.delete:
DELETE FROM ddd_log_comment
WHERE comment_number = #{commentNumber}
  AND user_number = #{userNumber}
